body:
Hi,

There seem to be a bug that leads to incorrect sha256 values for 64 bytes buffers. 

The broken sequence: `submit(64 bytes, ISAL_HASH_FIRST) ` -> `submit(0 bytes, ISAL_HASH_LAST)` -> `flush()` -> `Wrong Hash`
The working one:  `submit(0 bytes, ISAL_HASH_FIRST)` -> `submit(64 bytes, ISAL_HASH_LAST)` -> `flush()` -> `Correct Hash`
I'd expect the value to be the same and correct regardless of the permutation. 

Environment:
```sh
➜  isa-l_crypto git:(master) ✗ uname -a
Linux DESKTOP-6315RI1 5.15.167.4-microsoft-standard-WSL2 #1 SMP Tue Nov 5 00:21:55 UTC 2024 x86_64 x86_64 x86_64 GNU/Linux
➜  isa-l_crypto git:(master) ✗ gcc -v
Target: x86_64-linux-gnu
gcc version 13.3.0 (Ubuntu 13.3.0-6ubuntu2~24.04) 
```
Minimal reproducible example:
- _main.c_
    ```c
    void
    correct(void *buffer, uint32_t size)
    {
            ISAL_SHA256_HASH_CTX_MGR manager;
            isal_sha256_ctx_mgr_init(&manager);

            ISAL_SHA256_HASH_CTX in, *out = NULL;
            isal_hash_ctx_init(&in);

            isal_sha256_ctx_mgr_submit(&manager, &in, &out, NULL, 0, ISAL_HASH_FIRST);
            isal_sha256_ctx_mgr_submit(&manager, &in, &out, buffer, size, ISAL_HASH_LAST);
            isal_sha256_ctx_mgr_flush(&manager, &out);

            printf("Correct: ");
            for (int i = 0; i < SHA256_DIGEST_NWORDS; i++) {
                    printf("%08x", in.job.result_digest[i]);
            }
            printf("\n");
    }

    void
    wrong(void *buffer, uint32_t size)
    {
            ISAL_SHA256_HASH_CTX_MGR manager;
            isal_sha256_ctx_mgr_init(&manager);

            ISAL_SHA256_HASH_CTX in, *out = NULL;
            isal_hash_ctx_init(&in);

            isal_sha256_ctx_mgr_submit(&manager, &in, &out, buffer, size, ISAL_HASH_FIRST);
            isal_sha256_ctx_mgr_submit(&manager, &in, &out, NULL, 0, ISAL_HASH_LAST); // <----- seems here the padded block is not considered
            isal_sha256_ctx_mgr_flush(&manager, &out);

            printf("Wrong:   ");
            for (int i = 0; i < SHA256_DIGEST_NWORDS; i++) {
                    printf("%08x", in.job.result_digest[i]);
            }
            printf("\n");
    }

    int
    main()
    {
            uint8_t buffer[64];
            memset(buffer, 'a', sizeof(buffer));
            printf("Buffer:  ");
            for (int i = 0; i < sizeof(buffer); i++) {
                    printf("%c", buffer[i]);
            }
            printf("\n");

            correct(buffer, sizeof(buffer));
            wrong(buffer, sizeof(buffer));
    }
    ```
- _output_
    ```sh
    ➜  isa-l_crypto git:(master) ✗ gcc -I$(pwd)/include -L$(pwd)/lib -o demo main.c -lisal_crypto
    ➜  isa-l_crypto git:(master) ✗ LD_LIBRARY_PATH=$(pwd)/lib ./demo                  
    Buffer:  aaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaa
    Correct: ffe054fe7ae0cb6dc65c3af9b61d5209f439851db43d0ba5997337df154668eb
    Wrong:   df5bb81ce81e0626fb45a8944fd40f31b25e6816d6d499c1ab90492900635e66
    ```
